insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s1-q1', 's1', 'open', 'De buurt heet ''Heights''. Hoe hoog ligt het - en waarom heet het dan zo?', null, null, 'Het is plat (''Trains Meadow''); ''Heights'' is marketing (prestige, echo van Brooklyn Heights).', 2, true, false, 0, true)
