insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s1-q2', 's1', 'mc', 'Voor wie werd deze buurt gebouwd - en wie werd geweerd?', '["Voor White Anglo-Saxon Protestants; geweerd: Joden, zwarte Amerikanen, en in de praktijk katholieken/Italianen/Grieken","Voor iedereen - er was geen selectie","Alleen voor Ieren en Italianen","Alleen voor niet-Engelssprekenden"]'::jsonb, 0, null, 2, false, false, 1, true)
