insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s2-q1', 's2', 'open', 'Welk wereldberoemd bordspel werd hier bedacht - door wat voor iemand?', null, null, 'Scrabble; door een werkloze architect (Alfred Butts). Beide nodig.', 2, true, false, 0, true)
