insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s2-q2', 's2', 'mc', 'Welke twee groepen waren de eersten die de exclusieve buurt binnendrongen in de jaren ''40?', '["Joodse New Yorkers en homoseksuele mannen","Colombianen en Mexicanen","Tibetanen en Nepalezen","Ieren en Italianen"]'::jsonb, 0, null, 1, false, false, 1, true)
