insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s4-q1', 's4', 'mc', 'Migranten sturen vanaf straten als deze geld naar huis (''remittances''). Hoeveel gaat er wereldwijd jaarlijks naar lage- en middeninkomenslanden?', '["~6 miljard dollar","~65 miljard dollar","~650 miljard dollar","~6 biljoen dollar"]'::jsonb, 2, null, 1, false, false, 0, true)
