insert into questions (id, group_id, type, prompt, options, correct_index, model_answer, points, is_timeline, discussion, sort_order, active) values ('s4-q2', 's4', 'open', 'Lorena Borjas werd ''de moeder van de trans-Latinx-gemeenschap van Queens'' genoemd. Wat deed ze hier op Roosevelt?', null, null, 'Outreach voor transvrouwen/sekswerkers/ongedocumenteerden: condooms en spuiten uitdelen, hiv-tests, borgsommen, opvang. Punt bij elke zinnige kern.', 2, false, false, 1, true)
